// Set the cookie expiration time to 30 days
const COOKIE_EXPIRATION = 30 * 24 * 60 * 60;

function setRememberMeCookie(username, passwordHash) {
    const cookieData = JSON.stringify({ username, passwordHash });
    document.cookie = `remember_me=${cookieData}; expires=${new Date(Date.now() + COOKIE_EXPIRATION * 1000).toUTCString()}; path=/; secure`;
}

function getRememberMeCookie() {
    const cookies = document.cookie.split(';');
    for (const cookie of cookies) {
        if (cookie.trim().startsWith('remember_me=')) {
            return JSON.parse(cookie.slice(12));
        }
    }
    return null;
}

function autoLogin() {
    const rememberMeCookie = getRememberMeCookie();
    if (rememberMeCookie) {
        // Assuming you have a function to validate the password hash
        // and a function to login the user
        login(rememberMeCookie.username, rememberMeCookie.passwordHash);
    }
}

// Example usage:
function login(username, passwordHash) {
    // Your legacy system's login logic here
    console.log(`Logging in user: ${username}`);
}

// Set up event listeners for form submission and page load
document.addEventListener('DOMContentLoaded', autoLogin);

const rememberMeCheckbox = document.getElementById('remember_me');
if (rememberMeCheckbox) {
    rememberMeCheckbox.addEventListener('change', () => {
        if (rememberMeCheckbox.checked) {
            const usernameInput = document.getElementById('username');
            const passwordInput = document.getElementById('password');
            setRememberMeCookie(usernameInput.value, passwordHash(passwordInput.value));
        }
    });
}

function passwordHash(password) {
    // Simple hash function for demonstration purposes only
    return crypto.createHash('sha256').update(password).digest('hex');
}